const ELEVENLABS_API_URL = 'https://api.elevenlabs.io/v1/text-to-speech';
const VOICE_ID = 'cgSgspJ2msm6clMCkdW9';
const MODEL_ID = 'eleven_v3';
const COLLECTION = 'tts-cache';
const BATCH_SIZE = 20; // ElevenLabs rate limits are stricter

// Clean text for natural pronunciation
function cleanForTTS(text) {
  let cleaned = text;
  cleaned = cleaned.replace(/\s*\([^)]*\)/g, '');
  cleaned = cleaned.replace(/\s*\/\s*/g, ' או ');
  return cleaned.replace(/\s+/g, ' ').trim();
}

function cacheKey(text) {
  return Buffer.from(`${text}__el_${VOICE_ID}`).toString('base64url');
}

async function callElevenLabsTTS(text) {
  const response = await fetch(`${ELEVENLABS_API_URL}/${VOICE_ID}`, {
    method: 'POST',
    headers: {
      'xi-api-key': process.env.ELEVENLABS_API_KEY,
      'Content-Type': 'application/json',
      'Accept': 'audio/mpeg',
    },
    body: JSON.stringify({
      text,
      model_id: MODEL_ID,
      voice_settings: {
        stability: 0.5,
        similarity_boost: 0.75,
      },
    }),
  });

  if (response.status === 429) return { rateLimited: true };
  if (!response.ok) {
    const err = await response.text();
    throw new Error(`ElevenLabs TTS ${response.status}: ${err}`);
  }

  const arrayBuffer = await response.arrayBuffer();
  return { audioContent: Buffer.from(arrayBuffer).toString('base64') };
}

export default async function handler(req, res) {
  if (handleCors(req, res)) return;

  const db = getFirestore();

  // Find uncached texts
  const allDocs = await db.collection(COLLECTION).get();
  const existing = new Set();
  allDocs.forEach(doc => existing.add(doc.id));

  const missing = hebrewTexts.filter(t => !existing.has(cacheKey(t)));

  if (missing.length === 0) {
    return res.status(200).json({
      message: 'All translations cached',
      total: hebrewTexts.length,
      cached: existing.size,
    });
  }

  // Process a batch
  const batch = missing.slice(0, BATCH_SIZE);
  const results = { success: 0, failed: 0, rateLimited: 0, processed: [] };

  for (const text of batch) {
    try {
      const result = await callElevenLabsTTS(cleanForTTS(text));

      if (result?.rateLimited) {
        results.rateLimited++;
        break;
      }

      if (result?.audioContent) {
        await db.collection(COLLECTION).doc(cacheKey(text)).set({
          audio: result.audioContent,
          mimeType: 'audio/mpeg',
          text,
          voice: VOICE_ID,
          provider: 'elevenlabs',
          createdAt: new Date().toISOString(),
        });
        results.success++;
        results.processed.push(text);
      } else {
        results.failed++;
      }
    } catch (e) {
      results.failed++;
    }

    // Delay between requests for ElevenLabs rate limits
    await new Promise(r => setTimeout(r, 500));
  }

  return res.status(200).json({
    ...results,
    remaining: missing.length - results.success,
    total: hebrewTexts.length,
    cached: existing.size + results.success,
  });
}
